import { Box, Button, Heading, Icon, Text, VStack } from "@chakra-ui/react";
import { FaExclamationTriangle } from "react-icons/fa";
import { Link } from "react-router-dom";
import Navbar from "./Navbar";

const PageNotFound = () => {
  return (
    <Box bg="#f7f9fa" minH="100vh">
      
      {/* Navbar */}
      <Navbar />

      {/* Content */}
      <Box
        pt="100px"
        display="flex"
        justifyContent="center"
        alignItems="center"
      >
        <Box
          bg="#ffffff"
          border="1px solid #e5e7eb"
          borderRadius="12px"
          p={10}
          textAlign="center"
          boxShadow="lg"
          maxW="500px"
          w="90%"
        >
          <VStack spacing={4}>
            <Icon
              as={FaExclamationTriangle}
              color="#A435F0"
              boxSize={12}
            />

            <Heading size="lg" color="#1c1d1f">
              404 - Page Not Found
            </Heading>

            <Text color="gray.500">
              Oops! The page you're looking for doesn't exist or has been moved.
            </Text>

            <Link to="/">
              <Button
                mt={4}
                bg="#A435F0"
                color="white"
                _hover={{ bg: "#8710d8" }}
              >
                Go back to homepage
              </Button>
            </Link>
          </VStack>
        </Box>
      </Box>
    </Box>
  );
};

export default PageNotFound;
